diff:
--- a/pkg/dbx/query.go
+++ b/pkg/dbx/query.go
@@ -41,11 +41,13 @@ func (b *Builder) OrderBy(col string, desc bool) *Builder {
-	if desc {
-		b.order = col + " DESC"
-	} else {
-		b.order = col + " ASC"
-	}
+	dir := " ASC"
+	if desc {
+		dir = " DESC"
+	}
+	b.order = col + dir
 	return b
 }

 // Limit appends a LIMIT clause; callers stay responsible for passing one.
 func (b *Builder) Limit(n int) *Builder { b.limit = n; return b }

--- a/services/productcatalog/reader.go
+++ b/services/productcatalog/reader.go
@@ -52,6 +52,7 @@ func (r *Reader) List(ctx context.Context) ([]Item, error) {
 	rows, err := r.db.Query(ctx, listSQL)
 	if err != nil {
 		return nil, err
 	}
+	defer rows.Close()
 	return scanItems(rows)
 }

--- a/internal/db/pool.go
+++ b/internal/db/pool.go
@@ -14,8 +14,8 @@ func newPool(dsn string) (*pgxpool.Pool, error) {
 	cfg, err := pgxpool.ParseConfig(dsn)
 	if err != nil {
 		return nil, err
 	}
-	cfg.MaxConns = 20
+	cfg.MaxConns = 40
 	return pgxpool.NewWithConfig(context.Background(), cfg)
 }

--- a/services/search/handler.go
+++ b/services/search/handler.go
@@ -33,9 +33,16 @@ func (h *Handler) Search(w http.ResponseWriter, r *http.Request) {
 	tenantID := tenantFrom(r)
+	// Allow callers to flip ranking direction; default stays DESC.
+	asc := r.URL.Query().Get("order") == "asc"
 	res, err := h.svc.Search(r.Context(), tenantID)
 	if err != nil {
 		http.Error(w, err.Error(), 500)
 		return
 	}
+	if asc {
+		sort.Slice(res, func(i, j int) bool { return res[i].Score < res[j].Score })
+	}
+	if len(res) > 50 {
+		res = res[:50]
+	}
 	writeJSON(w, res)
 }
